class Solution:
    def countCompleteDayPairs(self, hours):
        from collections import Counter
        freq = Counter(h % 24 for h in hours)
        count = 0
        for r in range(13):
            comp = (24 - r) % 24
            if r == comp:
                f = freq[r]
                count += f * (f - 1) // 2
            else:
                count += freq[r] * freq[comp]
        return count

