var countCompleteDayPairs = function(hours) {
    const freq = new Array(24).fill(0);
    for (const h of hours) freq[h % 24]++;
    let count = 0;
    for (let r = 0; r < 13; r++) {
        const comp = (24 - r) % 24;
        if (r === comp) {
            const f = freq[r];
            count += f * (f - 1) / 2;
        } else {
            count += freq[r] * freq[comp];
        }
    }
    return count;
};
